import React, { useState, useEffect, useRef } from 'react';
import Navbar from '../components/Navbar';
import Sidebar from '../components/Sidebar';
import SpeechRecorder from '../components/SpeechRecorder';
import ScoreCard from '../components/ScoreCard';
import api from '../services/api';

const CHALLENGES = [
    {
        id: 'c1', title: '30-Second Elevator Pitch', icon: '🛗', durationSeconds: 30,
        category: 'Career', xpReward: 80, description: 'Sell yourself in exactly 30 seconds. Imagine you\'re in a lift with your dream employer.',
        tip: 'Start with a hook: "I help companies do X by doing Y."'
    },
    {
        id: 'c2', title: 'Explain a Random Object', icon: '🎲', durationSeconds: 60,
        category: 'Creativity', xpReward: 60, description: 'Pick any object near you and explain how it works to a 5-year-old.',
        tip: 'Use analogies and simple words. No jargon allowed!'
    },
    {
        id: 'c3', title: 'Debate Quickfire', icon: '⚡', durationSeconds: 45,
        category: 'Debate', xpReward: 90, description: 'You have 45 seconds to passionately argue FOR remote work. Go!',
        tip: 'Open with a bold statement, give 2 reasons, end with a call to action.'
    },
    {
        id: 'c4', title: 'Storytelling Challenge', icon: '📖', durationSeconds: 90,
        category: 'Storytelling', xpReward: 100, description: 'Tell a story using exactly these 3 words: dragon, coffee, deadline.',
        tip: 'Use the Pixar formula: Once upon a time… Until one day… Because of that…'
    },
    {
        id: 'c5', title: 'Mirror Talk', icon: '📺', durationSeconds: 60,
        category: 'Confidence', xpReward: 70, description: 'Introduce yourself as if you\'re on national TV being interviewed.',
        tip: 'Stand up, smile, and speak to the camera. Posture is half the battle.'
    },
    {
        id: 'c6', title: 'The Opposite Debate', icon: '🔄', durationSeconds: 30,
        category: 'Debate', xpReward: 85, description: 'Argue against something you strongly believe in. 30 seconds.',
        tip: 'Steel-man the opposing view. Great communicators understand both sides.'
    },
];

const CATEGORY_COLORS = {
    Career: 'bg-primary-500/20 text-primary-400 border-primary-500/30',
    Creativity: 'bg-accent-500/20 text-accent-400 border-accent-500/30',
    Debate: 'bg-neon-pink/20 text-neon-pink border-neon-pink/30',
    Storytelling: 'bg-neon-yellow/20 text-neon-yellow border-neon-yellow/30',
    Confidence: 'bg-neon-green/20 text-neon-green border-neon-green/30',
};

const FUN_MESSAGES = [
    "Nice! Your confidence is louder than your mic. 🎤",
    "Grammar police approve this performance. 👮",
    "Even CEOs started with an awkward first pitch. You're past that! 🔑",
    "Your voice has entered the room before you. That's a win! 🚀",
    "Achievement unlocked: Communication Legend in the making! 🏆",
];

/* ─── Countdown Timer ────────────────────────────────────────── */
function CountdownTimer({ seconds, onExpire }) {
    const [remaining, setRemaining] = useState(seconds);
    const [started, setStarted] = useState(false);
    const intervalRef = useRef(null);

    useEffect(() => {
        if (!started) return;
        intervalRef.current = setInterval(() => {
            setRemaining(prev => {
                if (prev <= 1) {
                    clearInterval(intervalRef.current);
                    onExpire?.();
                    return 0;
                }
                return prev - 1;
            });
        }, 1000);
        return () => clearInterval(intervalRef.current);
    }, [started, onExpire]);

    const pct = ((seconds - remaining) / seconds) * 100;
    const ring = 2 * Math.PI * 40;
    const color = remaining < 5 ? '#ff5caa' : remaining < seconds * 0.4 ? '#ffe600' : '#00e5a0';

    return (
        <div className="flex flex-col items-center gap-4">
            <div className="relative w-28 h-28">
                <svg className="w-28 h-28 -rotate-90" viewBox="0 0 96 96">
                    <circle cx="48" cy="48" r="40" fill="none" stroke="rgba(255,255,255,0.06)" strokeWidth="8" />
                    <circle cx="48" cy="48" r="40" fill="none" stroke={color} strokeWidth="8"
                        strokeLinecap="round" strokeDasharray={ring}
                        strokeDashoffset={ring * (1 - pct / 100)}
                        style={{ transition: 'stroke-dashoffset 0.8s ease' }} />
                </svg>
                <div className="absolute inset-0 flex flex-col items-center justify-center">
                    <span className="text-white font-bold text-3xl">{remaining}</span>
                    <span className="text-white/40 text-[10px]">sec</span>
                </div>
            </div>
            {!started && remaining === seconds && (
                <button
                    onClick={() => setStarted(true)}
                    className="px-6 py-2 rounded-xl bg-gradient-to-r from-primary-500 to-accent-500
                               text-white font-semibold text-sm hover:opacity-90 shadow-neon-blue transition"
                >
                    ▶ Start Timer
                </button>
            )}
        </div>
    );
}

/* ─── Challenge Card ─────────────────────────────────────────── */
function ChallengeCard({ challenge, onSelect }) {
    return (
        <button
            onClick={() => onSelect(challenge)}
            className="glass-card p-5 text-left hover:border-primary-500/40 hover:shadow-neon-blue
                       transition-all duration-200 group space-y-3"
        >
            <div className="flex items-center justify-between">
                <span className="text-4xl group-hover:scale-110 transition-transform duration-300">
                    {challenge.icon}
                </span>
                <div className="text-right space-y-1">
                    <span className={`text-[10px] px-2 py-0.5 rounded-full border font-semibold ${CATEGORY_COLORS[challenge.category] || ''}`}>
                        {challenge.category}
                    </span>
                    <p className="text-neon-green font-bold text-xs">+{challenge.xpReward} XP</p>
                </div>
            </div>
            <div>
                <p className="text-white font-semibold text-sm leading-tight">{challenge.title}</p>
                <p className="text-white/40 text-xs mt-1 leading-snug">{challenge.description}</p>
            </div>
            <div className="flex items-center gap-2 text-white/30 text-xs">
                <span>⏱ {challenge.durationSeconds}s</span>
                <span className="ml-auto text-primary-400 group-hover:translate-x-1 transition-transform">Start →</span>
            </div>
        </button>
    );
}

/* ─── Active Challenge Arena ─────────────────────────────────── */
function ChallengeArena({ challenge, onBack }) {
    const [scores, setScores] = useState(null);
    const [feedback, setFeedback] = useState('');
    const [tips, setTips] = useState([]);
    const [loading, setLoading] = useState(false);
    const [encouragement, setEncouragement] = useState('');

    const handleRecordingComplete = async (blob, duration) => {
        if (!blob) return;
        setLoading(true);
        setScores(null);
        try {
            const form = new FormData();
            form.append('audio', blob, 'challenge.webm');
            form.append('metadata', JSON.stringify({ challengeId: challenge.id, duration }));
            const res = await api.post(`/api/challenges/${challenge.id}/submit`, form, {
                headers: { 'Content-Type': 'multipart/form-data' },
            });
            setScores(res.data?.scores || null);
            setFeedback(res.data?.scores
                ? 'Your challenge is scored! Check the radar below.'
                : '');
            setTips(res.data?.improvementTips
                ? (typeof res.data.improvementTips === 'string'
                    ? res.data.improvementTips.split('|')
                    : res.data.improvementTips)
                : []);
            setEncouragement(res.data?.encouragement || FUN_MESSAGES[Math.floor(Math.random() * FUN_MESSAGES.length)]);
        } catch {
            // Fallback demo scoring
            const base = 60 + Math.random() * 35;
            setScores({
                overall: Math.round(base),
                fluency: +(55 + Math.random() * 40).toFixed(1),
                grammar: +(55 + Math.random() * 40).toFixed(1),
                vocabulary: +(50 + Math.random() * 45).toFixed(1),
                pronunciation: +(50 + Math.random() * 45).toFixed(1),
                confidence: +(50 + Math.random() * 45).toFixed(1),
            });
            setFeedback('');
            setTips(['Reduce filler words by replacing them with deliberate 1-second pauses.',
                'Vary your pitch to maintain listener engagement throughout.']);
            setEncouragement(FUN_MESSAGES[Math.floor(Math.random() * FUN_MESSAGES.length)]);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="space-y-5 animate-fadeInUp">
            <button onClick={onBack} className="text-white/40 hover:text-white text-sm flex items-center gap-1 transition">
                ← Back to Challenges
            </button>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-5">
                {/* Left: Timer + Recorder */}
                <div className="space-y-4">
                    <div className="glass-card p-6 space-y-4">
                        <div className="flex items-center gap-3">
                            <span className="text-4xl">{challenge.icon}</span>
                            <div>
                                <h3 className="text-white font-bold">{challenge.title}</h3>
                                <span className={`text-[10px] px-2 py-0.5 rounded-full border font-semibold ${CATEGORY_COLORS[challenge.category] || ''}`}>
                                    {challenge.category}
                                </span>
                            </div>
                        </div>
                        <p className="text-white/60 text-sm">{challenge.description}</p>
                        <div className="p-3 rounded-xl bg-neon-yellow/10 border border-neon-yellow/20">
                            <p className="text-neon-yellow text-xs">💡 Tip: {challenge.tip}</p>
                        </div>
                    </div>

                    <div className="glass-card p-6 flex flex-col items-center gap-4">
                        <p className="text-white/50 text-sm">Your time limit</p>
                        <CountdownTimer seconds={challenge.durationSeconds} />
                    </div>

                    <div className="glass-card p-5">
                        <h4 className="text-white font-semibold text-sm mb-3">Record Your Response</h4>
                        <SpeechRecorder
                            onRecordingComplete={handleRecordingComplete}
                            maxDuration={challenge.durationSeconds + 10}
                        />
                    </div>
                </div>

                {/* Right: ScoreCard */}
                <div className="space-y-4">
                    <ScoreCard scores={scores} feedback={feedback} improvementTips={tips} loading={loading} />
                    {encouragement && scores && (
                        <div className="glass-card p-4 text-center animate-fadeInUp">
                            <p className="text-2xl mb-2">🎉</p>
                            <p className="text-white font-semibold text-sm">{encouragement}</p>
                            <p className="text-neon-green text-xs mt-1">+{challenge.xpReward} XP earned!</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

/* ─── Main Page ──────────────────────────────────────────────── */
export default function Challenges() {
    const [sidebarOpen, setSidebarOpen] = useState(false);
    const [selected, setSelected] = useState(null);

    return (
        <div className="min-h-screen bg-dark-900 flex">
            <Sidebar open={sidebarOpen} onClose={() => setSidebarOpen(false)} />

            <div className="flex-1 flex flex-col min-w-0">
                <Navbar onMenuClick={() => setSidebarOpen(true)} />

                <main className="flex-1 p-4 md:p-6 space-y-6 overflow-y-auto">
                    {!selected ? (
                        <>
                            {/* Header */}
                            <div>
                                <h2 className="section-title text-2xl">🏆 Speaking Challenges</h2>
                                <p className="section-subtitle">
                                    Quick, high-intensity speaking drills. Timer on. Mic ready. Let's go.
                                </p>
                            </div>

                            {/* Banner */}
                            <div className="glass-card p-4 flex items-center gap-4 border-l-4 border-l-neon-pink">
                                <div className="text-3xl">⚡</div>
                                <div>
                                    <p className="text-white font-semibold text-sm">How it works</p>
                                    <p className="text-white/50 text-xs">
                                        Pick a challenge → read the prompt → hit Start Timer → speak when ready →
                                        submit your recording for instant AI-powered scoring.
                                    </p>
                                </div>
                            </div>

                            {/* Challenge Grid */}
                            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                                {CHALLENGES.map(c => (
                                    <ChallengeCard key={c.id} challenge={c} onSelect={setSelected} />
                                ))}
                            </div>
                        </>
                    ) : (
                        <ChallengeArena challenge={selected} onBack={() => setSelected(null)} />
                    )}
                </main>
            </div>
        </div>
    );
}
